let parsed;
try { parsed = JSON.parse($json.body || '{}'); } catch (e) { return [{ json: { valid: false, status: 400 } }]; }
const fs = require('fs');
const path = require('path');
let activeProjects = [];
try { activeProjects = JSON.parse(fs.readFileSync(path.join('Shared', 'processed_projects.json'), 'utf8')); } catch (e) {}
if (!parsed.project_prefix || !activeProjects.includes(parsed.project_prefix)) {
  return [{ json: { valid: false, status: 400 } }];
}
if (!parsed.typed_name || !parsed.consent === true) {
  return [{ json: { valid: false, status: 400 } }];
}
return [{ json: { valid: true, project_prefix: parsed.project_prefix, typed_name: parsed.typed_name, ip: $json.headers['x-forwarded-for'] || $json.headers['remote-addr'] || '', consent: true } }];

// Signature record saved SYNCHRONOUSLY into durable, project-scoped
// operational state -- contact-hash-scoped, not only in the ephemeral
// intake_cache/. This is what the retry queue later points to, never
// duplicates (A9).

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const email = $json.email || $json.typed_name; // signature step precedes email capture on some flows; hash on best available identity
const hash = crypto.createHash('sha256').update(String(email).toLowerCase().trim()).digest('hex');

const record = {
  contact_hash: hash,
  project_prefix: $json.project_prefix,
  typed_name: $json.typed_name,
  timestamp: new Date().toISOString(),
  ip: $json.ip,
  consent: true
};

const dir = path.join('Working', $json.project_prefix, 'signatures');
fs.mkdirSync(dir, { recursive: true });
fs.writeFileSync(path.join(dir, hash + '.json'), JSON.stringify(record, null, 2), 'utf8');

return [{ json: record }];

// pdf-lib background generation. Sanitizes typed_name first (alphanumeric
// + punctuation only) before it touches PDF metadata. Output path is
// contact-hash + fresh random token -- never shared or fixed (A9).

const crypto = require('crypto');

const safeName = String($json.typed_name).replace(/[^\w\s.,'-]/g, '').slice(0, 200);
const runToken = crypto.randomBytes(8).toString('hex');
const outPath = `Working/${$json.project_prefix}/pdf_output/tmp_${$json.contact_hash}_${runToken}.pdf`;

try {
  const { PDFDocument, rgb } = require('pdf-lib');
  const fs = require('fs');
  const path = require('path');

  const templateBytes = fs.readFileSync(path.join('Originals', 'brand_shell', 'nda_template.pdf'));
  const pdfDoc = await PDFDocument.load(templateBytes);
  pdfDoc.setSubject('Executed NDA - ' + $json.project_prefix);
  pdfDoc.setKeywords([safeName, $json.timestamp]);

  const page = pdfDoc.getPages()[0];
  page.drawText(safeName, { x: 72, y: 100, size: 12, color: rgb(0, 0, 0) });
  page.drawText('Signed: ' + $json.timestamp + ' from ' + $json.ip, { x: 72, y: 80, size: 8 });

  fs.mkdirSync(path.dirname(outPath), { recursive: true });
  const bytes = await pdfDoc.save();
  fs.writeFileSync(outPath, bytes);

  return [{ json: { ...$json, pdf_generated: true, pdf_path: outPath } }];
} catch (e) {
  return [{ json: { ...$json, pdf_generated: false, error: String(e.message || e) } }];
}

// On failure: strip the heavy payload entirely, serialize only minimal
// metadata as a POINTER to the durable signature record already saved
// above -- never a duplicate of it. Staggered delay, explicit slot
// release, no in-memory buffer held across the wait (A9/B1).

const fs = require('fs');
const path = require('path');

let queue = [];
const queuePath = path.join('Working', 'cache', 'retry_queue.tmp');
try { queue = JSON.parse(fs.readFileSync(queuePath, 'utf8')); } catch (e) {}

const existing = queue.find(q => q.contact_hash === $json.contact_hash && q.project_prefix === $json.project_prefix);
const attemptCount = existing ? existing.attempt_count + 1 : 1;

queue = queue.filter(q => !(q.contact_hash === $json.contact_hash && q.project_prefix === $json.project_prefix));
queue.push({
  contact_hash: $json.contact_hash,
  project_prefix: $json.project_prefix,
  attempt_count: attemptCount,
  next_attempt_after: new Date(Date.now() + attemptCount * 60000).toISOString()
});

fs.mkdirSync(path.dirname(queuePath), { recursive: true });
fs.writeFileSync(queuePath, JSON.stringify(queue, null, 2), 'utf8');

// $json's own pdf/text buffers are not carried forward -- this node's
// output is metadata only, execution ends here for this attempt.
return [{ json: { contact_hash: $json.contact_hash, project_prefix: $json.project_prefix, queued_for_retry: true, attempt_count: attemptCount } }];
